package picod

import (
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"errors"
	"fmt"
	"net/http"
	"os"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

const (
	MaxBodySize      = 32 << 20
	PublicKeyEnvVar  = "PICOD_AUTH_PUBLIC_KEY"
)

var (
	ErrMissingAuthHeader = errors.New("missing authorization header")
	ErrInvalidAuthFormat = errors.New("invalid authorization format")
	ErrInvalidToken      = errors.New("invalid token")
)

type AuthManager struct {
	publicKey *rsa.PublicKey
	mutex     sync.RWMutex
}

func NewAuthManager() *AuthManager {
	return &AuthManager{}
}

func (am *AuthManager) LoadPublicKeyFromEnv() error {
	keyPEM := os.Getenv(PublicKeyEnvVar)
	if keyPEM == "" {
		return fmt.Errorf("%s environment variable is required", PublicKeyEnvVar)
	}

	block, _ := pem.Decode([]byte(keyPEM))
	if block == nil {
		return errors.New("failed to parse PEM block containing the public key")
	}

	if block.Type != "PUBLIC KEY" {
		return fmt.Errorf("invalid PEM block type: expected PUBLIC KEY, got %s", block.Type)
	}

	pub, err := x509.ParsePKIXPublicKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	rsaPub, ok := pub.(*rsa.PublicKey)
	if !ok {
		return errors.New("not an RSA public key")
	}

	am.mutex.Lock()
	defer am.mutex.Unlock()

	am.publicKey = rsaPub
	return nil
}

func (am *AuthManager) AuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{
				"error":  "Missing Authorization header",
				"code":   http.StatusUnauthorized,
				"detail": "JWT authentication required",
			})
			c.Abort()
			return
		}

		tokenString, err := extractBearerToken(authHeader)
		if err != nil {
			c.JSON(http.StatusUnauthorized, gin.H{
				"error":  err.Error(),
				"code":   http.StatusUnauthorized,
				"detail": "Use Bearer <token>",
			})
			c.Abort()
			return
		}

		am.mutex.RLock()
		publicKey := am.publicKey
		am.mutex.RUnlock()

		if publicKey == nil {
			c.JSON(http.StatusUnauthorized, gin.H{
				"error":  "Public key not loaded",
				"code":   http.StatusUnauthorized,
				"detail": "Server configuration error",
			})
			c.Abort()
			return
		}

		token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
			if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
			}
			return publicKey, nil
		}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(time.Minute))

		if err != nil || !token.Valid {
			detail := "Token validation failed"
			if err != nil {
				detail = err.Error()
			}
			c.JSON(http.StatusUnauthorized, gin.H{
				"error":  "Invalid token",
				"code":   http.StatusUnauthorized,
				"detail": detail,
			})
			c.Abort()
			return
		}

		c.Request.Body = http.MaxBytesReader(c.Writer, c.Request.Body, MaxBodySize)
		c.Next()
	}
}

func extractBearerToken(authHeader string) (string, error) {
	const bearerPrefix = "Bearer "
	if len(authHeader) < len(bearerPrefix) || authHeader[:len(bearerPrefix)] != bearerPrefix {
		return "", ErrInvalidAuthFormat
	}
	return authHeader[len(bearerPrefix):], nil
}

