package picod

import (
	"encoding/base64"
	"fmt"
	"io"
	"mime"
	"net/http"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
)

const (
	maxFileMode = 0777
)

var workspaceDir string

func SetWorkspaceDir(dir string) {
	workspaceDir = dir
}

func sanitizePath(p string) (string, error) {
	if workspaceDir == "" {
		return "", fmt.Errorf("workspace directory not initialized")
	}

	realWorkspace, err := filepath.EvalSymlinks(workspaceDir)
	if err != nil {
		realWorkspace = filepath.Clean(workspaceDir)
	}

	cleanPath := filepath.Clean(p)
	if filepath.IsAbs(cleanPath) {
		cleanPath = strings.TrimPrefix(cleanPath, "/")
	}

	fullPath := filepath.Join(realWorkspace, cleanPath)

	relPath, err := filepath.Rel(realWorkspace, fullPath)
	if err != nil || strings.HasPrefix(relPath, "..") {
		return "", fmt.Errorf("access denied: path outside workspace")
	}

	realPath, err := filepath.EvalSymlinks(fullPath)
	if err == nil {
		relPath, err = filepath.Rel(realWorkspace, realPath)
		if err != nil || strings.HasPrefix(relPath, "..") {
			return "", fmt.Errorf("access denied: symlink resolves outside workspace")
		}
		return realPath, nil
	}

	if os.IsNotExist(err) {
		return fullPath, nil
	}

	return "", err
}

type FileInfo struct {
	Path     string    `json:"path"`
	Size     int64     `json:"size"`
	Mode     string    `json:"mode"`
	Modified time.Time `json:"modified"`
}

type ListFilesResponse struct {
	Files []FileEntry `json:"files"`
}

type FileEntry struct {
	Name     string    `json:"name"`
	Size     int64     `json:"size"`
	Modified time.Time `json:"modified"`
	Mode     string    `json:"mode"`
	IsDir    bool      `json:"is_dir"`
}

func parseFileMode(modeStr string) os.FileMode {
	if modeStr == "" {
		return 0644
	}

	mode, err := strconv.ParseUint(modeStr, 8, 32)
	if err != nil || mode > maxFileMode {
		return 0644
	}

	return os.FileMode(mode)
}

func UploadFileHandler(c *gin.Context) {
	contentType := c.GetHeader("Content-Type")

	if strings.HasPrefix(contentType, "multipart/form-data") {
		handleMultipartUpload(c)
		return
	}

	handleJSONBase64Upload(c)
}

func handleMultipartUpload(c *gin.Context) {
	path := c.Request.FormValue("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Missing 'path' form field",
			"code":  http.StatusBadRequest,
		})
		return
	}

	file, header, err := c.Request.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Missing or invalid 'file' in multipart form",
			"code":  http.StatusBadRequest,
		})
		return
	}
	defer file.Close()

	modeStr := c.Request.FormValue("mode")
	mode := parseFileMode(modeStr)

	sanitizedPath, err := sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  http.StatusBadRequest,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to create directories",
			"code":  http.StatusInternalServerError,
		})
		return
	}

	outFile, err := os.OpenFile(sanitizedPath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, mode)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to create file",
			"code":  http.StatusInternalServerError,
		})
		return
	}
	defer outFile.Close()

	if _, err := io.Copy(outFile, file); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to write file content",
			"code":  http.StatusInternalServerError,
		})
		return
	}

	stat, err := outFile.Stat()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to get file info",
			"code":  http.StatusInternalServerError,
		})
		return
	}

	relPath, _ := filepath.Rel(workspaceDir, sanitizedPath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     stat.Size(),
		Mode:     stat.Mode().String(),
		Modified: stat.ModTime(),
	})
}

func handleJSONBase64Upload(c *gin.Context) {
	var req struct {
		Path    string `json:"path"`
		Content string `json:"content"`
		Mode    string `json:"mode"`
	}

	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("Invalid JSON: %v", err),
			"code":  http.StatusBadRequest,
		})
		return
	}

	if req.Path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Missing 'path' in request",
			"code":  http.StatusBadRequest,
		})
		return
	}

	content, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Invalid base64 content",
			"code":  http.StatusBadRequest,
		})
		return
	}

	mode := parseFileMode(req.Mode)

	sanitizedPath, err := sanitizePath(req.Path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  http.StatusBadRequest,
		})
		return
	}

	if err := os.MkdirAll(filepath.Dir(sanitizedPath), 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to create directories",
			"code":  http.StatusInternalServerError,
		})
		return
	}

	if err := os.WriteFile(sanitizedPath, content, mode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to write file",
			"code":  http.StatusInternalServerError,
		})
		return
	}

	stat, err := os.Stat(sanitizedPath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to get file info",
			"code":  http.StatusInternalServerError,
		})
		return
	}

	relPath, _ := filepath.Rel(workspaceDir, sanitizedPath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     relPath,
		Size:     stat.Size(),
		Mode:     stat.Mode().String(),
		Modified: stat.ModTime(),
	})
}

func ListFilesHandler(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Missing 'path' query parameter",
			"code":  http.StatusBadRequest,
		})
		return
	}

	sanitizedPath, err := sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  http.StatusBadRequest,
		})
		return
	}

	entries, err := os.ReadDir(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{
				"error": "Directory not found",
				"code":  http.StatusNotFound,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to read directory",
			"code":  http.StatusInternalServerError,
		})
		return
	}

	files := make([]FileEntry, 0, len(entries))
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue
		}

		files = append(files, FileEntry{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime(),
			Mode:     info.Mode().String(),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, ListFilesResponse{Files: files})
}

func DownloadFileHandler(c *gin.Context) {
	path := c.Param("path")

	sanitizedPath, err := sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  http.StatusBadRequest,
		})
		return
	}

	stat, err := os.Stat(sanitizedPath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{
				"error": "File not found",
				"code":  http.StatusNotFound,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to stat file",
			"code":  http.StatusInternalServerError,
		})
		return
	}

	if stat.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Path is a directory, not a file",
			"code":  http.StatusBadRequest,
		})
		return
	}

	basename := filepath.Base(sanitizedPath)
	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=\"%s\"", basename))

	contentType := mime.TypeByExtension(filepath.Ext(sanitizedPath))
	if contentType == "" {
		contentType = "application/octet-stream"
	}
	c.Header("Content-Type", contentType)

	c.File(sanitizedPath)
}

