const (
	DefaultTimeout   = 60 * time.Second
	TimeoutExitCode  = 124
)

type ExecuteRequest struct {
	Command    []string          `json:"command"`
	Timeout    string            `json:"timeout,omitempty"`
	WorkingDir string            `json:"working_dir,omitempty"`
	Env        map[string]string `json:"env,omitempty"`
}

type ExecuteResponse struct {
	Stdout    string `json:"stdout"`
	Stderr    string `json:"stderr"`
	ExitCode  int    `json:"exit_code"`
	Duration  string `json:"duration"`
	StartTime string `json:"start_time"`
	EndTime   string `json:"end_time"`
}

func ExecuteHandler(c *gin.Context) {
	var req ExecuteRequest

	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  http.StatusBadRequest,
		})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "command cannot be empty",
			"code":  http.StatusBadRequest,
		})
		return
	}

	timeout := DefaultTimeout
	if req.Timeout != "" {
		var err error
		timeout, err = time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("invalid timeout format: %v", err),
				"code":  http.StatusBadRequest,
			})
			return
		}
	}

	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	cmd := exec.CommandContext(ctx, req.Command[0], req.Command[1:]...)

	if req.WorkingDir != "" {
		workingDir, err := sanitizePath(req.WorkingDir)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("Invalid working directory: %v", err),
				"code":  http.StatusBadRequest,
			})
			return
		}
		cmd.Dir = workingDir
	} else if workspaceDir != "" {
		cmd.Dir = workspaceDir
	}

	cmd.Env = append(os.Environ(), envMapToSlice(req.Env)...)

	var stdoutBuf, stderrBuf strings.Builder
	cmd.Stdout = &stdoutBuf
	cmd.Stderr = &stderrBuf

	startTime := time.Now()
	err := cmd.Run()
	endTime := time.Now()
	duration := endTime.Sub(startTime)

	exitCode := 0
	if err != nil {
		if ctx.Err() == context.DeadlineExceeded {
			exitCode = TimeoutExitCode
			stderrBuf.WriteString(fmt.Sprintf("\nCommand timed out after %d seconds", int(timeout.Seconds())))
		} else if exitErr, ok := err.(*exec.ExitError); ok {
			exitCode = exitErr.ExitCode()
		} else {
			c.JSON(http.StatusInternalServerError, gin.H{
				"error": err.Error(),
				"code":  http.StatusInternalServerError,
			})
			return
		}
	}

	c.JSON(http.StatusOK, ExecuteResponse{
		Stdout:    stdoutBuf.String(),
		Stderr:    stderrBuf.String(),
		ExitCode:  exitCode,
		Duration:  duration.String(),
		StartTime: startTime.Format(time.RFC3339),
		EndTime:   endTime.Format(time.RFC3339),
	})
