func NewServer(config *Config) (*Server, error) {
	server := &Server{
		Config: config,
	}

	SetWorkspaceDir(config.Workspace)

	return server, nil
}

func (s *Server) Run() error {
	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Logger(), gin.Recovery())

	authManager := NewAuthManager()
	if err := authManager.LoadPublicKeyFromEnv(); err != nil {
		log.Fatalf("Failed to load public key: %v", err)
	}

	apiGroup := engine.Group("/api")
	apiGroup.Use(authManager.AuthMiddleware())
	{
		apiGroup.POST("/execute", ExecuteHandler)
		apiGroup.POST("/files", UploadFileHandler)
		apiGroup.GET("/files", ListFilesHandler)
		apiGroup.GET("/files/*path", DownloadFileHandler)
	}

	engine.GET("/health", HealthHandler)

	server := &http.Server{
		Addr:              fmt.Sprintf(":%d", s.Config.Port),
		Handler:           h2c.NewHandler(engine, &http2.Server{}),
		ReadHeaderTimeout: 10 * time.Second,
	}

	stopChan := make(chan os.Signal, 1)
	signal.Notify(stopChan, os.Interrupt, syscall.SIGTERM)

	go func() {
		log.Printf("Starting PicoD server on port %d", s.Config.Port)
		log.Printf("Workspace directory: %s", s.Config.Workspace)
		if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			log.Fatalf("Server failed: %v", err)
		}
	}()

	<-stopChan
	log.Println("Shutting down server...")

	ctx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()

	if err := server.Shutdown(ctx); err != nil {
		return fmt.Errorf("server shutdown error: %w", err)
	}

	log.Println("Server stopped")
	return nil
}

