package picod

import (
	"flag"
	"fmt"
	"os"
)

type Config struct {
	Port      int
	Workspace string
}

type Server struct {
	Config *Config
}

func ParseFlags() *Config {
	config := &Config{}

	flag.IntVar(&config.Port, "port", 8080, "Port to listen on")
	flag.StringVar(&config.Workspace, "workspace", "", "Workspace directory (defaults to current working directory)")

	flag.Parse()

	if config.Workspace == "" {
		wd, err := os.Getwd()
		if err != nil {
			fmt.Fprintf(os.Stderr, "Failed to get working directory: %v\n", err)
			os.Exit(1)
		}
		config.Workspace = wd
	}

	return config
}

